import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { darkTheme, lightTheme } from '../styles/theme';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  // 1. Initialize from localStorage or default to 'dark'
  const [theme, setTheme] = useState(() => {
    return localStorage.getItem('finify-ui-preference') || 'dark';
  });

  /**
   * 🏛️ Style Injection Logic
   * Maps JS theme objects to CSS custom properties on the :root element.
   */
  const applyThemeVariables = useCallback((themeName) => {
    const root = document.documentElement;
    const themeObject = themeName === 'dark' ? darkTheme : lightTheme;

    // Batch update CSS variables for performance
    Object.keys(themeObject).forEach((property) => {
      root.style.setProperty(property, themeObject[property]);
    });

    // Toggle the .dark class for Tailwind's darkMode: 'class' strategy
    if (themeName === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, []);

  // 2. Apply theme on mount and whenever it changes
  useEffect(() => {
    applyThemeVariables(theme);
    localStorage.setItem('finify-ui-preference', theme);
  }, [theme, applyThemeVariables]);

  const toggleTheme = () => {
    setTheme((prev) => (prev === 'dark' ? 'light' : 'dark'));
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

/**
 * 🛡️ Defensive Hook
 * Ensures the theme engine isn't accessed outside its provider node.
 */
export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error("THEME_ENGINE_FAILURE: useTheme must be used within a ThemeProvider.");
  }
  return context;
};
